var sdk = window.CueStack;
var wsCount = 0, mqttCount = 0;
var allData = [];
var MAX_POINTS = 100;
var currentChannel = 'sensor-room-a';
var mqttClient = null;
var orgShort = '';

var canvas = document.createElement('canvas');
document.getElementById('chartArea').appendChild(canvas);
requestAnimationFrame(drawChart);

fetch('/api/channels', {credentials: 'include'}).then(function(r) { return r.json(); }).then(function(data) {
  orgShort = data.connection.org_short;
  connectAll();
});

function connectAll() {
  connectWebSocket();
  connectMQTT();
  loadHistory();
}

function connectWebSocket() {
  sdk.subscribe(currentChannel, function(msg) {
    var d = msg.data || msg;
    wsCount++;
    document.getElementById('wsCount').textContent = wsCount;
    document.getElementById('wsTemp').textContent = (d.temperature || 0).toFixed(1) + '°C';
    document.getElementById('wsHumid').textContent = (d.humidity || 0).toFixed(1) + '%';
    allData.push(d);
    if (allData.length > MAX_POINTS) allData.shift();
  });
  setBadge('wsStatus', 'Connected', '#f0fde8', '#15803d');
}

function connectMQTT() {
  if (mqttClient) { mqttClient.end(); }
  var loc = window.parent ? window.parent.location : window.location;
  var wsUrl = (loc.protocol === 'https:' ? 'wss://' : 'ws://') + loc.host + '/ws/mqtt';
  mqttClient = mqtt.connect(wsUrl, {
    clientId: 'dashboard-' + Math.random().toString(36).substr(2, 8),
    clean: true,
  });
  mqttClient.on('connect', function() {
    var topic = 'org/' + orgShort + '/' + currentChannel;
    mqttClient.subscribe(topic);
    setBadge('mqttStatus', 'Subscribed: ' + topic, '#f0fde8', '#15803d');
  });
  mqttClient.on('message', function(topic, message) {
    try {
      var d = JSON.parse(message.toString());
      mqttCount++;
      document.getElementById('mqttCount').textContent = mqttCount;
      document.getElementById('mqttTemp').textContent = (d.temperature || 0).toFixed(1) + '°C';
      document.getElementById('mqttHumid').textContent = (d.humidity || 0).toFixed(1) + '%';
    } catch(e) {}
  });
  mqttClient.on('error', function() { setBadge('mqttStatus', 'Error', '#fef2f2', '#dc2626'); });
}

async function loadHistory() {
  setBadge('chStatus', 'Loading...', '#fefce8', '#a16207');
  try {
    var data = await sdk.queryEvents({ channel: currentChannel, limit: 50 });
    var events = data.events || [];
    document.getElementById('chRows').textContent = events.length;
    document.getElementById('chLatest').textContent = events.length > 0 ? new Date(events[0].timestamp).toLocaleTimeString() : '--';
    document.getElementById('chTime').textContent = new Date().toLocaleTimeString();
    setBadge('chStatus', events.length + ' rows', '#f0fde8', '#15803d');
    var head = document.getElementById('tableHead');
    var body = document.getElementById('tableBody');
    if (events.length === 0) { body.innerHTML = '<tr><td colspan="3">No data yet. Start the simulator.</td></tr>'; return; }
    head.innerHTML = '<th>Time</th><th>Channel</th><th>Payload</th>';
    body.innerHTML = events.map(function(e) {
      return '<tr><td>' + new Date(e.timestamp).toLocaleTimeString() + '</td><td>' + (e.channel || '') + '</td><td>' + (e.payload || '').substring(0, 60) + '</td></tr>';
    }).join('');
  } catch(e) { setBadge('chStatus', 'Error', '#fef2f2', '#dc2626'); }
}

function switchChannel() {
  currentChannel = document.getElementById('channel').value;
  wsCount = 0; mqttCount = 0;
  document.getElementById('wsCount').textContent = '0';
  document.getElementById('mqttCount').textContent = '0';
  allData = [];
  connectAll();
}

function setBadge(id, text, bg, color) {
  var el = document.getElementById(id);
  el.textContent = text; el.style.background = bg; el.style.color = color;
}

function drawChart() {
  var w = canvas.parentElement.clientWidth;
  var h = canvas.parentElement.clientHeight;
  canvas.width = w; canvas.height = h;
  var ctx = canvas.getContext('2d');
  ctx.fillStyle = '#1e1e1e'; ctx.fillRect(0, 0, w, h);
  if (allData.length < 2) { requestAnimationFrame(drawChart); return; }
  var temps = allData.map(function(d) { return d.temperature || 0; });
  var minT = Math.min.apply(null, temps) - 1, maxT = Math.max.apply(null, temps) + 1;
  ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2; ctx.beginPath();
  allData.forEach(function(d, i) {
    var x = (i / (MAX_POINTS - 1)) * w;
    var y = h - (((d.temperature || 0) - minT) / (maxT - minT)) * h;
    i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
  }); ctx.stroke();
  var humids = allData.map(function(d) { return d.humidity || 0; });
  var minH = Math.min.apply(null, humids) - 1, maxH = Math.max.apply(null, humids) + 1;
  ctx.strokeStyle = '#3b82f6'; ctx.beginPath();
  allData.forEach(function(d, i) {
    var x = (i / (MAX_POINTS - 1)) * w;
    var y = h - (((d.humidity || 0) - minH) / (maxH - minH)) * h;
    i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
  }); ctx.stroke();
  ctx.fillStyle = '#ef4444'; ctx.font = '11px monospace';
  ctx.fillText('Temp: ' + temps[temps.length-1].toFixed(1) + ' (WS:' + wsCount + ' MQTT:' + mqttCount + ')', 8, 14);
  ctx.fillStyle = '#3b82f6';
  ctx.fillText('Humid: ' + humids[humids.length-1].toFixed(1) + '%', 8, 28);
  requestAnimationFrame(drawChart);
}
